 924 InstructionCost VPInstruction::computeCost(ElementCount VF,
 925                                            VPCostContext &Ctx) const {
 926   if (Instruction::isBinaryOp(getOpcode())) {
 927     Type *ResTy = Ctx.Types.inferScalarType(this);
 928     if (!vputils::onlyFirstLaneUsed(this))
 929       ResTy = toVectorTy(ResTy, VF);
 930 
 931     if (!getUnderlyingValue()) {
 932       switch (getOpcode()) {
 933       case Instruction::FMul:
 934         return Ctx.TTI.getArithmeticInstrCost(getOpcode(), ResTy, Ctx.CostKind);
 935       default:
 936         // TODO: Compute cost for VPInstructions without underlying values once
 937         // the legacy cost model has been retired.
 938         return 0;
 939       }
 940     }
 941 
 942     assert(!doesGeneratePerAllLanes() &&
 943            "Should only generate a vector value or single scalar, not scalars "
 944            "for all lanes.");
 945     return Ctx.TTI.getArithmeticInstrCost(getOpcode(), ResTy, Ctx.CostKind);
 946   }
 947 
 948   switch (getOpcode()) {
 949   case Instruction::ExtractElement:
 950   case VPInstruction::ExtractLane: {
 951     // Add on the cost of extracting the element.
 952     auto *VecTy = toVectorTy(Ctx.Types.inferScalarType(getOperand(0)), VF);
 953     return Ctx.TTI.getVectorInstrCost(Instruction::ExtractElement, VecTy,
 954                                       Ctx.CostKind);
 955   }
 956   case VPInstruction::AnyOf: {
 957     auto *VecTy = toVectorTy(Ctx.Types.inferScalarType(this), VF);
 958     return Ctx.TTI.getArithmeticReductionCost(
 959         Instruction::Or, cast<VectorType>(VecTy), std::nullopt, Ctx.CostKind);
 960   }
 961   case VPInstruction::FirstActiveLane: {
 962     // Calculate the cost of determining the lane index.
 963     auto *PredTy = toVectorTy(Ctx.Types.inferScalarType(getOperand(0)), VF);
 964     IntrinsicCostAttributes Attrs(Intrinsic::experimental_cttz_elts,
 965                                   Type::getInt64Ty(Ctx.LLVMCtx),
 966                                   {PredTy, Type::getInt1Ty(Ctx.LLVMCtx)});
 967     return Ctx.TTI.getIntrinsicInstrCost(Attrs, Ctx.CostKind);
 968   }
 969   case VPInstruction::FirstOrderRecurrenceSplice: {
 970     assert(VF.isVector() && "Scalar FirstOrderRecurrenceSplice?");
 971     SmallVector<int> Mask(VF.getKnownMinValue());
 972     std::iota(Mask.begin(), Mask.end(), VF.getKnownMinValue() - 1);
 973     Type *VectorTy = toVectorTy(Ctx.Types.inferScalarType(this), VF);
 974 
 975     return Ctx.TTI.getShuffleCost(TargetTransformInfo::SK_Splice,
 976                                   cast<VectorType>(VectorTy),
 977                                   cast<VectorType>(VectorTy), Mask,
 978                                   Ctx.CostKind, VF.getKnownMinValue() - 1);
 979   }
 980   case VPInstruction::ActiveLaneMask: {
 981     Type *ArgTy = Ctx.Types.inferScalarType(getOperand(0));
 982     Type *RetTy = toVectorTy(Type::getInt1Ty(Ctx.LLVMCtx), VF);
 983     IntrinsicCostAttributes Attrs(Intrinsic::get_active_lane_mask, RetTy,
 984                                   {ArgTy, ArgTy});
 985     return Ctx.TTI.getIntrinsicInstrCost(Attrs, Ctx.CostKind);
 986   }
 987   case VPInstruction::ExplicitVectorLength: {
 988     Type *Arg0Ty = Ctx.Types.inferScalarType(getOperand(0));
